import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import Navbar from '../../home/components/Navbar';
import Footer from '../../home/components/Footer';
import { supabase } from '../../../lib/supabase';

interface Club {
  id: string;
  name: string;
  description: string;
  category: string;
  coordinator_name: string;
  coordinator_email: string;
  coordinator_phone: string;
  meeting_schedule: string;
  achievements: string;
  display_order: number;
}

interface ClubPhoto {
  id: string;
  club_id: string;
  photo_url: string;
  caption: string;
}

export default function ClubsPage() {
  const navigate = useNavigate();
  const [clubs, setClubs] = useState<Club[]>([]);
  const [clubPhotos, setClubPhotos] = useState<{ [key: string]: ClubPhoto[] }>({});
  const [selectedCategory, setSelectedCategory] = useState<string>('all');
  const [loading, setLoading] = useState(true);

  const breadcrumbs = [
    { label: 'Home', path: '/' },
    { label: 'Co-Curricular', path: '#' },
    { label: 'Clubs', path: '/co-curricular/clubs' }
  ];

  const categories = [
    { id: 'all', name: 'All Clubs', icon: 'ri-apps-line', color: 'from-gray-600 to-gray-700' },
    { id: 'technical', name: 'Technical', icon: 'ri-code-box-line', color: 'from-blue-600 to-cyan-600' },
    { id: 'cultural', name: 'Cultural', icon: 'ri-music-line', color: 'from-purple-600 to-pink-600' },
    { id: 'sports', name: 'Sports', icon: 'ri-basketball-line', color: 'from-green-600 to-teal-600' },
    { id: 'social', name: 'Social Service', icon: 'ri-heart-line', color: 'from-red-600 to-orange-600' },
    { id: 'literary', name: 'Literary', icon: 'ri-book-open-line', color: 'from-indigo-600 to-purple-600' }
  ];

  useEffect(() => {
    fetchClubs();
  }, []);

  const fetchClubs = async () => {
    try {
      setLoading(true);
      const { data: clubsData, error: clubsError } = await supabase
        .from('clubs')
        .select('*')
        .order('display_order', { ascending: true });

      if (clubsError) throw clubsError;

      if (clubsData) {
        setClubs(clubsData);

        const { data: photosData, error: photosError } = await supabase
          .from('club_photos')
          .select('*')
          .order('display_order', { ascending: true });

        if (photosError) throw photosError;

        if (photosData) {
          const photosByClub: { [key: string]: ClubPhoto[] } = {};
          photosData.forEach((photo) => {
            if (!photosByClub[photo.club_id]) {
              photosByClub[photo.club_id] = [];
            }
            photosByClub[photo.club_id].push(photo);
          });
          setClubPhotos(photosByClub);
        }
      }
    } catch (error) {
      console.error('Error fetching clubs:', error);
    } finally {
      setLoading(false);
    }
  };

  const filteredClubs = selectedCategory === 'all'
    ? clubs
    : clubs.filter(club => club.category === selectedCategory);

  const getCategoryColor = (category: string) => {
    const cat = categories.find(c => c.id === category);
    return cat ? cat.color : 'from-gray-600 to-gray-700';
  };

  const getCategoryIcon = (category: string) => {
    const cat = categories.find(c => c.id === category);
    return cat ? cat.icon : 'ri-apps-line';
  };

  const openClub = (club: Club) => {
    const slug = club.name
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-+|-+$/g, '');
    window.scrollTo({ top: 0, behavior: 'instant' });
    navigate(`/co-curricular/clubs/${slug}`);
  };

  return (
    <div className="min-h-screen bg-white">
      <Navbar scrolled={true} />

      {/* Breadcrumb */}
      <div className="bg-gray-50 border-b border-gray-200 mt-28">
        <div className="max-w-7xl mx-auto px-6 py-4">
          <nav className="flex items-center space-x-2 text-sm">
            {breadcrumbs.map((crumb, index) => (
              <div key={index} className="flex items-center">
                {index > 0 && <i className="ri-arrow-right-s-line text-gray-400 mx-2"></i>}
                <a href={crumb.path}
                  className={`${index === breadcrumbs.length - 1
                    ? 'text-teal-600 font-semibold'
                    : 'text-gray-600 hover:text-teal-600'
                  } transition-colors duration-200 cursor-pointer`}>
                  {crumb.label}
                </a>
              </div>
            ))}
          </nav>
        </div>
      </div>

      {/* Hero */}
      <div className="relative bg-gradient-to-br from-teal-600 via-cyan-600 to-blue-600 text-white py-24">
        <div className="absolute inset-0 bg-black/20"></div>
        <div className="relative max-w-7xl mx-auto px-6">
          <div className="flex items-center justify-center mb-6">
            <div className="w-24 h-24 bg-white/10 backdrop-blur-sm rounded-2xl flex items-center justify-center">
              <i className="ri-team-line text-6xl"></i>
            </div>
          </div>
          <h1 className="text-5xl font-bold text-center mb-4">Student Clubs</h1>
          <p className="text-xl text-center text-white/90 max-w-3xl mx-auto">
            Explore diverse clubs fostering creativity, leadership, and holistic development
          </p>
        </div>
      </div>

      {/* Category Filter */}
      <div className="bg-white border-b border-gray-200 sticky top-28 z-40 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 py-6">
          <div className="flex flex-wrap gap-3 justify-center">
            {categories.map((category) => (
              <button key={category.id} onClick={() => setSelectedCategory(category.id)}
                className={`flex items-center space-x-2 px-6 py-3 rounded-full font-semibold transition-all duration-300 whitespace-nowrap ${
                  selectedCategory === category.id
                    ? `bg-gradient-to-r ${category.color} text-white shadow-lg`
                    : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                }`}>
                <i className={`${category.icon} text-lg`}></i>
                <span>{category.name}</span>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Clubs Grid */}
      <section className="py-20 bg-gradient-to-br from-gray-50 to-white">
        <div className="max-w-7xl mx-auto px-6">
          {loading ? (
            <div className="flex justify-center items-center py-20">
              <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-teal-600"></div>
            </div>
          ) : filteredClubs.length === 0 ? (
            <div className="text-center py-20">
              <i className="ri-inbox-line text-6xl text-gray-400 mb-4"></i>
              <p className="text-xl text-gray-600">No clubs found in this category</p>
            </div>
          ) : (
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredClubs.map((club) => (
                <div key={club.id}
                  className="bg-white rounded-2xl overflow-hidden shadow-lg hover:shadow-2xl transition-all duration-300 border border-gray-100 cursor-pointer"
                  onClick={() => openClub(club)}>

                  {/* Club Image */}
                  <div className="aspect-video w-full overflow-hidden bg-gradient-to-br from-gray-100 to-gray-200">
                    {clubPhotos[club.id] && clubPhotos[club.id][0] ? (
                      <img src={clubPhotos[club.id][0].photo_url} alt={club.name}
                        className="w-full h-full object-cover" />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center">
                        <i className={`${getCategoryIcon(club.category)} text-6xl text-gray-400`}></i>
                      </div>
                    )}
                  </div>

                  {/* Club Info */}
                  <div className="p-6">
                    <div className={`inline-block px-3 py-1 rounded-full text-xs font-semibold text-white bg-gradient-to-r ${getCategoryColor(club.category)} mb-3`}>
                      {club.category.charAt(0).toUpperCase() + club.category.slice(1)}
                    </div>
                    <h3 className="text-2xl font-bold text-gray-900 mb-3">{club.name}</h3>
                    <p className="text-gray-600 mb-4 line-clamp-3">{club.description}</p>

                    {club.coordinator_name && (
                      <div className="flex items-center text-sm text-gray-700 mb-2">
                        <i className="ri-user-line mr-2 text-teal-600"></i>
                        <span className="font-semibold">{club.coordinator_name}</span>
                      </div>
                    )}

                    {clubPhotos[club.id] && clubPhotos[club.id].length > 0 && (
                      <div className="flex items-center text-sm text-gray-600 mt-4">
                        <i className="ri-image-line mr-2"></i>
                        <span>{clubPhotos[club.id].length} photos</span>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>

      <Footer />
    </div>
  );
}